from flask import Flask, request, session, redirect, url_for
from flask_mfa import MFA

app = Flask(__name__)
app.config["SECRET_KEY"] = "secret"

# Initialize the MFA extension
mfa = MFA(app)

@app.route("/login", methods=["POST"])
def login():
    # Get the username and password from the request body
    username = request.form["username"]
    password = request.form["password"]

    # Check if the user is enabled for MFA
    mfa_enabled = session["mfa_enabled"]

    # If MFA is enabled, prompt for the OTP
    if mfa_enabled:
        otp = request.form["otp"]
        if not mfa.verify(username, password, otp):
            return "Invalid OTP", 401

    # Grant access to the user
    session["user"] = username
    return redirect(url_for("index"))

@app.route("/api/direct-login", methods=["POST"])
def direct_login():
    # Get the username and password from the request body
    username = request.form["username"]
    password = request.form["password"]

    # Grant access to the user without checking for MFA
    session["user"] = username
    return redirect(url_for("index"))

@app.route("/")
def index():
    # Check if the user is logged in
    if "user" not in session:
        return redirect(url_for("login"))

    # Display a welcome message to the user
    return f"Welcome, {session['user']}!"